unit lipdecide;

{$mode objfpc}{$H+}

interface

uses
  globals, Math;

function REALCOMPARE(A, B: real): COMPTYPE;
procedure DECIDE;

implementation

{ Compare two real numbers using six significant digits. }
function REALCOMPARE(A, B: real): COMPTYPE;
var
  maxAbs, scale, scaledA, scaledB: real;
  expVal: integer;
  intA, intB: int64;
begin
  maxAbs := abs(A);
  if abs(B) > maxAbs then
    maxAbs := abs(B);

  if maxAbs = 0 then
    exit(EQ);

  expVal := Floor(log10(maxAbs));
  scale := power(10.0, expVal - 5);  { leaves six significant digits when rounding }

  scaledA := A / scale;
  scaledB := B / scale;

  intA := Round(scaledA);
  intB := Round(scaledB);

  if intA < intB then
    Result := LT
  else if intA > intB then
    Result := GT
  else
    Result := EQ;
end;

{ Helper functions }
function Distance(idx1, idx2: integer): real;
var
  dx, dy: real;
begin
  dx := X[idx2] - X[idx1];
  dy := Y[idx2] - Y[idx1];
  Distance := sqrt(dx * dx + dy * dy);
end;

function TriangleArea(idx1, idx2, idx3: integer): real;
var
  area2: real;
begin
  area2 := abs(X[idx1] * (Y[idx2] - Y[idx3]) +
               X[idx2] * (Y[idx3] - Y[idx1]) +
               X[idx3] * (Y[idx1] - Y[idx2]));
  TriangleArea := area2 / 2.0;
end;

function MinCircleRadius(idx1, idx2, idx3: integer): real;
var
  a, b, c, maxSide, other1, other2, area2, denom: real;
begin
  a := Distance(idx2, idx3);
  b := Distance(idx1, idx3);
  c := Distance(idx1, idx2);

  maxSide := a;
  other1 := b;
  other2 := c;
  if (b > maxSide) then
  begin
    maxSide := b;
    other1 := a;
    other2 := c;
  end;
  if (c > maxSide) then
  begin
    maxSide := c;
    other1 := a;
    other2 := b;
  end;

  area2 := abs(X[idx1] * (Y[idx2] - Y[idx3]) +
               X[idx2] * (Y[idx3] - Y[idx1]) +
               X[idx3] * (Y[idx1] - Y[idx2]));

  if REALCOMPARE(area2, 0.0) = EQ then
  begin
    MinCircleRadius := maxSide / 2.0;
    exit;
  end;

  { If the triangle is obtuse or right at the vertex opposite the longest side,
    the minimum enclosing circle has that side as diameter. }
  if REALCOMPARE(maxSide * maxSide, other1 * other1 + other2 * other2) <> LT then
  begin
    MinCircleRadius := maxSide / 2.0;
    exit;
  end;

  denom := 2.0 * area2; { since area = area2/2, 4*area = 2*area2 }
  MinCircleRadius := (a * b * c) / denom;
end;

function AngleDefined(idx1, idx2, idx3: integer; out angle: real): boolean;
var
  ux, uy, vx, vy, dotp, normu, normv, cosTheta: real;
begin
  { angle at idx2 (vertex) }
  if (REALCOMPARE(X[idx1], X[idx2]) = EQ) and (REALCOMPARE(Y[idx1], Y[idx2]) = EQ) then
  begin
    Result := False;
    exit;
  end;
  if (REALCOMPARE(X[idx3], X[idx2]) = EQ) and (REALCOMPARE(Y[idx3], Y[idx2]) = EQ) then
  begin
    Result := False;
    exit;
  end;

  ux := X[idx1] - X[idx2];
  uy := Y[idx1] - Y[idx2];
  vx := X[idx3] - X[idx2];
  vy := Y[idx3] - Y[idx2];

  normu := sqrt(ux * ux + uy * uy);
  normv := sqrt(vx * vx + vy * vy);

  if (REALCOMPARE(normu, 0.0) = EQ) or (REALCOMPARE(normv, 0.0) = EQ) then
  begin
    Result := False;
    exit;
  end;

  dotp := ux * vx + uy * vy;
  cosTheta := dotp / (normu * normv);
  if cosTheta > 1.0 then cosTheta := 1.0;
  if cosTheta < -1.0 then cosTheta := -1.0;
  angle := arccos(cosTheta);
  Result := True;
end;

function Quadrant(xv, yv: real): integer;
begin
  if REALCOMPARE(yv, 0.0) = GT then
  begin
    if REALCOMPARE(xv, 0.0) = LT then
      Quadrant := 2
    else
      Quadrant := 1;
  end
  else if REALCOMPARE(yv, 0.0) = EQ then
  begin
    if REALCOMPARE(xv, 0.0) = LT then
      Quadrant := 2
    else
      Quadrant := 1;
  end
  else { y < 0 }
  begin
    if REALCOMPARE(xv, 0.0) = GT then
      Quadrant := 4
    else
      Quadrant := 3;
  end;
end;

function DistancePointLine(ax, ay, bx, by, px, py: real): real;
var
  dx, dy, num, den: real;
begin
  dx := bx - ax;
  dy := by - ay;

  if (REALCOMPARE(dx, 0.0) = EQ) and (REALCOMPARE(dy, 0.0) = EQ) then
  begin
    DistancePointLine := sqrt(sqr(px - ax) + sqr(py - ay));
    exit;
  end;

  num := abs(dy * px - dx * py + bx * ay - by * ax);
  den := sqrt(dx * dx + dy * dy);
  DistancePointLine := num / den;
end;

{ Individual LIC evaluations }
function LIC1: boolean;
var
  i: integer;
begin
  Result := False;
  for i := 1 to NUMPOINTS - 1 do
    if REALCOMPARE(Distance(i, i + 1), PARAMETERS.LENGTH1) = GT then
      exit(True);
end;

function LIC2: boolean;
var
  i: integer;
begin
  Result := False;
  for i := 1 to NUMPOINTS - 2 do
    if REALCOMPARE(MinCircleRadius(i, i + 1, i + 2), PARAMETERS.RADIUS1) = GT then
      exit(True);
end;

function LIC3: boolean;
var
  i: integer;
  angle: real;
begin
  Result := False;
  for i := 1 to NUMPOINTS - 2 do
    if AngleDefined(i, i + 1, i + 2, angle) then
    begin
      if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or
         (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
        exit(True);
    end;
end;

function LIC4: boolean;
var
  i: integer;
begin
  Result := False;
  for i := 1 to NUMPOINTS - 2 do
    if REALCOMPARE(TriangleArea(i, i + 1, i + 2), PARAMETERS.AREA1) = GT then
      exit(True);
end;

function LIC5: boolean;
var
  i, j, quad: integer;
  seen: array[1..4] of boolean;
  count: integer;
begin
  Result := False;
  if NUMPOINTS < PARAMETERS.Q_PTS then exit;

  for i := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    for quad := 1 to 4 do
      seen[quad] := False;

    for j := i to i + PARAMETERS.Q_PTS - 1 do
    begin
      quad := Quadrant(X[j], Y[j]);
      seen[quad] := True;
    end;

    count := 0;
    for quad := 1 to 4 do
      if seen[quad] then Inc(count);

    if count > PARAMETERS.QUADS then
      exit(True);
  end;
end;

function LIC6: boolean;
var
  i: integer;
begin
  Result := False;
  for i := 1 to NUMPOINTS - 1 do
    if REALCOMPARE(X[i + 1], X[i]) = LT then
      exit(True);
end;

function LIC7: boolean;
var
  i, j, endIdx: integer;
  dist: real;
  ax, ay, bx, by: real;
begin
  Result := False;
  if NUMPOINTS < 3 then exit;

  endIdx := NUMPOINTS - PARAMETERS.N_PTS + 1;
  for i := 1 to endIdx do
  begin
    ax := X[i]; ay := Y[i];
    bx := X[i + PARAMETERS.N_PTS - 1];
    by := Y[i + PARAMETERS.N_PTS - 1];

    for j := i to i + PARAMETERS.N_PTS - 1 do
    begin
      dist := DistancePointLine(ax, ay, bx, by, X[j], Y[j]);
      if REALCOMPARE(dist, PARAMETERS.DIST) = GT then
        exit(True);
    end;
  end;
end;

function LIC8: boolean;
var
  i, j: integer;
begin
  Result := False;
  if NUMPOINTS < 3 then exit;
  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    j := i + PARAMETERS.K_PTS + 1;
    if REALCOMPARE(Distance(i, j), PARAMETERS.LENGTH1) = GT then
      exit(True);
  end;
end;

function LIC9: boolean;
var
  i, j, k, maxStart: integer;
begin
  Result := False;
  if NUMPOINTS < 5 then exit;

  maxStart := NUMPOINTS - (PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2);
  for i := 1 to maxStart do
  begin
    j := i + PARAMETERS.A_PTS + 1;
    k := j + PARAMETERS.B_PTS + 1;
    if REALCOMPARE(MinCircleRadius(i, j, k), PARAMETERS.RADIUS1) = GT then
      exit(True);
  end;
end;

function LIC10: boolean;
var
  i, j, k, maxStart: integer;
  angle: real;
begin
  Result := False;
  if NUMPOINTS < 5 then exit;

  maxStart := NUMPOINTS - (PARAMETERS.C_PTS + PARAMETERS.D_PTS + 2);
  for i := 1 to maxStart do
  begin
    j := i + PARAMETERS.C_PTS + 1;
    k := j + PARAMETERS.D_PTS + 1;
    if AngleDefined(i, j, k, angle) then
      if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or
         (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
        exit(True);
  end;
end;

function LIC11: boolean;
var
  i, j, k, maxStart: integer;
begin
  Result := False;
  if NUMPOINTS < 5 then exit;

  maxStart := NUMPOINTS - (PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2);
  for i := 1 to maxStart do
  begin
    j := i + PARAMETERS.E_PTS + 1;
    k := j + PARAMETERS.F_PTS + 1;
    if REALCOMPARE(TriangleArea(i, j, k), PARAMETERS.AREA1) = GT then
      exit(True);
  end;
end;

function LIC12: boolean;
var
  i, j: integer;
begin
  Result := False;
  if NUMPOINTS < 3 then exit;
  for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
  begin
    j := i + PARAMETERS.G_PTS + 1;
    if REALCOMPARE(X[j], X[i]) = LT then
      exit(True);
  end;
end;

function LIC13: boolean;
var
  i, j: integer;
  foundGreater, foundLess: boolean;
  dist: real;
begin
  Result := False;
  if NUMPOINTS < 3 then exit;

  foundGreater := False;
  foundLess := False;
  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    j := i + PARAMETERS.K_PTS + 1;
    dist := Distance(i, j);
    if not foundGreater then
      if REALCOMPARE(dist, PARAMETERS.LENGTH1) = GT then
        foundGreater := True;
    if not foundLess then
      if REALCOMPARE(dist, PARAMETERS.LENGTH2) = LT then
        foundLess := True;
    if foundGreater and foundLess then
      exit(True);
  end;
end;

function LIC14: boolean;
var
  i, j, k, maxStart: integer;
  foundGT, foundLE: boolean;
  radius: real;
begin
  Result := False;
  if NUMPOINTS < 5 then exit;

  foundGT := False;
  foundLE := False;
  maxStart := NUMPOINTS - (PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2);
  for i := 1 to maxStart do
  begin
    j := i + PARAMETERS.A_PTS + 1;
    k := j + PARAMETERS.B_PTS + 1;
    radius := MinCircleRadius(i, j, k);
    if not foundGT then
      if REALCOMPARE(radius, PARAMETERS.RADIUS1) = GT then
        foundGT := True;
    if not foundLE then
      if (REALCOMPARE(radius, PARAMETERS.RADIUS2) = LT) or
         (REALCOMPARE(radius, PARAMETERS.RADIUS2) = EQ) then
        foundLE := True;
    if foundGT and foundLE then
      exit(True);
  end;
end;

function LIC15: boolean;
var
  i, j, k, maxStart: integer;
  foundGT, foundLT: boolean;
  area: real;
begin
  Result := False;
  if NUMPOINTS < 5 then exit;

  foundGT := False;
  foundLT := False;
  maxStart := NUMPOINTS - (PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2);
  for i := 1 to maxStart do
  begin
    j := i + PARAMETERS.E_PTS + 1;
    k := j + PARAMETERS.F_PTS + 1;
    area := TriangleArea(i, j, k);
    if (not foundGT) and (REALCOMPARE(area, PARAMETERS.AREA1) = GT) then
      foundGT := True;
    if (not foundLT) and (REALCOMPARE(area, PARAMETERS.AREA2) = LT) then
      foundLT := True;
    if foundGT and foundLT then
      exit(True);
  end;
end;

procedure BuildCMV;
begin
  CMV[1]  := LIC1;
  CMV[2]  := LIC2;
  CMV[3]  := LIC3;
  CMV[4]  := LIC4;
  CMV[5]  := LIC5;
  CMV[6]  := LIC6;
  CMV[7]  := LIC7;
  CMV[8]  := LIC8;
  CMV[9]  := LIC9;
  CMV[10] := LIC10;
  CMV[11] := LIC11;
  CMV[12] := LIC12;
  CMV[13] := LIC13;
  CMV[14] := LIC14;
  CMV[15] := LIC15;
end;

procedure BuildPUM;
var
  i, j: integer;
begin
  for i := 1 to 15 do
    for j := 1 to 15 do
    begin
      if i = j then
        continue;
      case LCM[i, j] of
        NOTUSED: PUM[i, j] := True;
        ANDD:    PUM[i, j] := CMV[i] and CMV[j];
        ORR:     PUM[i, j] := CMV[i] or CMV[j];
      end;
    end;
end;

procedure BuildFUV;
var
  i, j: integer;
  allTrue: boolean;
begin
  for i := 1 to 15 do
  begin
    if not PUM[i, i] then
      FUV[i] := True
    else
    begin
      allTrue := True;
      for j := 1 to 15 do
        if not PUM[i, j] then
        begin
          allTrue := False;
          break;
        end;
      FUV[i] := allTrue;
    end;
  end;
end;

procedure DecideLaunch;
var
  i: integer;
begin
  LAUNCH := True;
  for i := 1 to 15 do
    if not FUV[i] then
    begin
      LAUNCH := False;
      exit;
    end;
end;

procedure DECIDE;
begin
  BuildCMV;
  BuildPUM;
  BuildFUV;
  DecideLaunch;
end;

end.
